    private String getStatusEmoji(int code) {
        if (code >= 200 && code < 300) return "✅";
        if (code >= 300 && code < 400) return "🔀";
        if (code == 401 || code == 403) return "🔐";
        if (code == 404) return "🔍";
        if (code == 429) return "🚦";
        if (code >= 400 && code < 500) return "⚠️";
        if (code >= 500) return "🔥";
        return "📨";
    }

    private String getAuthType(String authHeader) {
        if (authHeader == null) return "none";
        if (authHeader.startsWith("Bearer ")) return "Bearer Token";
        if (authHeader.startsWith("Basic ")) return "Basic Auth";
        if (authHeader.startsWith("Digest ")) return "Digest Auth";
        if (authHeader.startsWith("HMAC ")) return "HMAC";
        return "Unknown (" + authHeader.substring(0, Math.min(authHeader.length(), 10)) + "...)";
    }

    private String getTokenPreview(String token) {
        if (token == null || token.length() < 10) return "[short token]";
        return token.substring(0, 6) + "..." + token.substring(token.length() - 4);
    }

    private boolean isSensitiveHeader(String headerName) {
        for (String sensitive : SENSITIVE_HEADERS) {
            if (sensitive.equalsIgnoreCase(headerName)) {
                return true;
            }
        }
        return false;
    }

    private String redactValue(String value) {
        if (value == null) return "[null]";
        if (value.length() <= 8) return "****";
        return value.substring(0, 4) + "****" + value.substring(value.length() - 4);
    }

    private boolean isReadableContentType(MediaType contentType) {
        if (contentType == null) return true;
        String type = contentType.type();
        String subtype = contentType.subtype();

        if ("text".equals(type)) return true;
        if ("application".equals(type)) {
            return "json".equals(subtype) ||
                    "xml".equals(subtype) ||
                    "javascript".equals(subtype) ||
                    "x-www-form-urlencoded".equals(subtype) ||
                    "graphql".equals(subtype) ||
                    subtype.endsWith("+json") ||
                    subtype.endsWith("+xml");
        }
        return false;
    }

    private Charset getCharset(MediaType contentType) {
        if (contentType != null) {
            Charset charset = contentType.charset(UTF8);
            if (charset != null) return charset;
        }
        return UTF8;
    }

    private String formatBody(String body, MediaType contentType) {
        if (body == null || body.isEmpty()) return "      [empty]";

        String indented = "      " + body.replace("\n", "\n      ");

        // Truncate very long bodies for log readability
        if (indented.length() > 10000) {
            return indented.substring(0, 10000) + "\n      ... [TRUNCATED - full body " + body.length() + " chars]";
        }

        return indented;
    }

